('متقدم 1', 'Advanced 1', 'تطبيقات سريرية متوسطة وتفسير العلامات الحيوية في حالات مرضية', 'Brain', '#7C3AED', 2, 65, 1500),
('متقدم 2', 'Advanced 2', 'حالات سريرية معقدة ومتلازمات طبية متقدمة', 'Trophy', '#DC2626', 3, 70, 1200);

-- ========== أسئلة المستوى الأساسي (25 سؤال) ==========
INSERT OR IGNORE INTO questions (category_id, level_id, topic, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, clinical_note, difficulty_weight, sort_order) VALUES
(1, 1, 'ضغط الدم', 'أفضل شريان لقياس ضغط الدم بالطرق غير المباشرة هو:', 'الكعبري', 'السباتي', 'العضدي', 'الفخذي', 'C', 'الشريان العضدي هو الأفضل لأنه قريب من القلب وكبير بما يكفي لسماع أصوات كوروتكوف بوضوح، والكعبري قد يصعب سماع الأصوات فيه في بعض المرضى.', 'الشريان العضدي يعطي قراءة أقرب للضغط المركزي مقارنة بالشريان الكعبري.', 1.0, 1),
(1, 1, 'ضغط الدم', 'عند استخدام جهاز الضغط، يجب أن يكون الكف:', 'أصغر من الذراع', 'أكبر من الذراع', 'مناسب لمحيط الذراع', 'مربوط بإحكام شديد', 'C', 'الكف يجب أن يغطي 80% من محيط الذراع. كف صغير يعطي قراءة مرتفعة كاذبة وكف كبير يعطي قراءة منخفضة كاذبة.', 'اختيار حجم خاطئ للكف من أكثر أخطاء قياس الضغط شيوعا.', 1.0, 2),
(1, 1, 'ضغط الدم', 'في حال سماع أصوات كوروتكوف الأولى فهذا يدل على:', 'الضغط الانبساطي', 'الضغط الانقباضي', 'توقف النبض', 'خطأ في القياس', 'B', 'الصوت الأول المسموع (المرحلة I من كوروتكوف) يمثل الضغط الانقباضي، وهو الضغط عندما يبدأ الدم بالتدفق خلال الشريان المضغوط.', 'أصوات كوروتكوف لها 5 مراحل، كل مرحلة لها دلالة سريرية.', 1.0, 3),
(1, 1, 'التشبع الأكسجيني', 'انخفاض تشبع الأكسجين أقل من 90% يعني:', 'حالة طبيعية', 'نقص أكسجة', 'ارتفاع ضغط', 'جفاف', 'B', 'القيم الطبيعية لـ SpO2 هي 95-100%. انخفاضه عن 90% يعتبر نقص أكسجة (Hypoxia) ويستدعي تدخل فوري.', 'قد لا تظهر الزرقة سريريا حتى ينخفض التشبع عن 85%.', 1.0, 4),
(1, 1, 'النبض', 'أفضل موضع لقياس النبض في مريض الصدمة:', 'الكعبري', 'السباتي', 'الظنبوبي', 'الرسغي', 'B', 'في حالات الصدمة يحدث تقلص محيطي يؤدي لضعف النبضات المحيطية. النبض السباتي هو المركزي وآخر ما يختفي، لذا هو الأكثر دقة لتقييم النبض في الطوارئ.', 'إذا كان النبض السباتي محسوسا والكعبري غائب، هذا مؤشر على صدمة شديدة.', 1.0, 5),
(1, 1, 'الحرارة', 'الفرق الطبيعي بين الحرارة الفموية والشرجية هو تقريبا:', '0.1 درجة', '0.3 درجة', '0.5 درجة', '1 درجة', 'C', 'الحرارة الشرجية أعلى من الفموية بـ 0.5 درجة تقريبا لأن الشرج أكثر داخليا وأقل تأثرا بالبيئة الخارجية.', 'الحرارة الإبطية أقل من الفموية بـ 0.5 درجة تقريبا.', 1.0, 6),
(1, 1, 'التنفس', 'عند قياس التنفس يجب أن:', 'يخبر المريض', 'لا يخبر المريض', 'يطلب منه العد', 'يطلب منه الكلام', 'B', 'إخبار المريض بقياس التنفس يجعله يغير معدل تنفسه لا إراديا. يقاس التنفس بعد قياس النبض مع الحفاظ على اليد على المعصم وكأننا لا نزال نقيس النبض.', 'هذه من المهارات الأساسية التي يخطئ فيها كثير من الممارسين الجدد.', 1.0, 7),
(1, 1, 'التنفس', 'بطء التنفس أقل من 12/دقيقة يسمى:', 'Tachypnea', 'Bradypnea', 'Apnea', 'Dyspnea', 'B', 'Bradypnea هو بطء التنفس عن المعدل الطبيعي (12-20 للبالغين). Tachypnea تسارع، Apnea توقف، Dyspnea صعوبة تنفس.', 'بطء التنفس قد يكون طبيعيا في الرياضيين أثناء الراحة، لكنه مقلق إذا ترافق مع تغير الوعي.', 1.0, 8),
(1, 1, 'النبض', 'النبض غير المنتظم مع دوار قد يدل على:', 'فقر دم', 'اضطراب نظم القلب', 'ربو', 'جفاف', 'B', 'عدم انتظام النبض (Arrhythmia) مع أعراض مثل الدوار يشير لاضطراب في النظم الكهربائي للقلب ويستدعي تسجيل ECG.', 'عدم انتظام النبض وحده قد يكون فسيولوجيا مثل عدم انتظام التنفس الجيبي.', 1.0, 9),
(1, 1, 'التفسير السريري', 'الضغط الانبساطي يمثل:', 'انقباض البطين', 'استرخاء البطين', 'انقباض الأذين', 'امتلاء الرئة', 'B', 'الضغط الانبساطي هو أدنى ضغط في الشرايين ويمثل مرحلة استرخاء البطين (Diastole) عندما تمتلئ عضلة القلب بالدم.', 'الضغط الانبساطي المرتفع (>90) يعتبر عامل خطر مستقل لأمراض القلب.', 1.0, 10),
(1, 1, 'التفسير السريري', 'الضغط الانقباضي يمثل:', 'استرخاء القلب', 'انقباض القلب', 'امتلاء الرئة', 'انبساط الشرايين', 'B', 'الضغط الانقباضي هو أعلى ضغط يحدث أثناء انقباض البطين (Systole) ويدفع الدم عبر الشرايين.', 'الضغط الانبساطي أهم من الانقباضي في تقييم خطر أمراض القلب بعد عمر 50.', 1.0, 11),
(1, 1, 'إجراءات القياس', 'أفضل وضعية للمريض أثناء قياس الضغط:', 'واقف', 'مستلقى', 'جالس والذراع بمستوى القلب', 'منبطح', 'C', 'الذراع يجب أن يكون بمستوى القلب. إذا كان أعلى يعطي قراءة منخفضة كاذبة، وإذا كان أسفل يعطي قراءة مرتفعة كاذبة.', 'وضعية الجلوس مع القدمين مسطحتين على الأرض هي الوضعية القياسية.', 1.0, 12),
(1, 1, 'التفسير السريري', 'زرقة الشفاه تشير إلى:', 'فقر دم', 'نقص أكسجين', 'ارتفاع سكر', 'جفاف', 'B', 'الزرقة المركزية (الشفاه واللسان) تشير لنقص أكسجة حقيقي على عكس الزرقة المحيطية التي قد تحدث من برودة الأطراف.', 'الزرقة قد لا تظهر في فقر الدم الشديد رغم نقص الأكسجين بسبب قلة الهيموجلوبين.', 1.0, 13),
(1, 1, 'التفسير السريري', 'النبض الخيطي يدل غالبا على:', 'صدمة', 'رياضي', 'قلق', 'حرارة مرتفعة', 'A', 'النبض الخيطي (Thready Pulse) ضعيف وسريع ولا يمكن إحساسه بوضوح، ويحدث في الصدمة بسبب انخفاض حجم الدم وازدياد معدل القلب كاستجابة تعويضية.', 'النبض الخيطي مع برودة الأطراف من علامات الصدمة المبكرة المهمة.', 1.0, 14),
(1, 1, 'التفسير السريري', 'ارتفاع الحرارة مع تسارع النبض يدل على:', 'زيادة الاستقلاب', 'فشل كلوي', 'ربو', 'قرحة', 'A', 'لكل درجة مئوية ارتفاع في الحرارة يزداد النبض 10-15 نبضة/دقيقة. هذه العلاقة تسمى قاعدة ليبرمايستر وتعكس زيادة الاستقلاب.', 'إذا ارتفعت الحرارة دون تسارع نبض متناسب، قد يشير لعدوى التيفوئيد أو بعض الأدوية.', 1.0, 15),
(1, 1, 'التشبع الأكسجيني', 'الجهاز المستخدم لقياس SpO2 هو:', 'ECG', 'Pulse Oximeter', 'Thermometer', 'Sphygmomanometer', 'B', 'جهاز قياس النبض بالأكسجين (Pulse Oximeter) يقيس نسبة الهيموجلوبين المشبع بالأكسجين عبر الأصبع أو الأذن.', 'النتائج قد تكون غير دقيقة في حالات تسمم أول أكسيد الكربون لأنه يعطي قراءة عالية كاذبة.', 1.0, 16),
(1, 1, 'إجراءات القياس', 'قياس الضغط بوضع الوقوف قد يسبب:', 'قراءة خاطئة', 'دقة أعلى', 'عدم تغير', 'انخفاض كاذب', 'A', 'الوقوف يسبب تجمع الدم في الأطراف السفلية مما يغير قراءة الضغط. القياس القياسي يكون بالجلوس أو الاستلقاء.', 'يقاس الضغط في الوضعين لاختبار هبوط الضغط الانتصابي (Orthostatic Hypotension).', 1.0, 17),
(1, 1, 'التفسير السريري', 'انخفاض الضغط عند الوقوف يسمى:', 'Hypertension', 'Orthostatic Hypotension', 'Shock', 'Arrhythmia', 'B', 'هبوط الضغط الانتصابي هو انخفاض الضغط الانقباضي >20 مم زئبق أو الانبساطي >10 مم زئبق عند الوقوف من الجلوس.', 'يحدث في الجفاف، بعض الأدوية، واعتلال الجهاز العصبي اللاإرادي.', 1.0, 18),
(1, 1, 'إجراءات القياس', 'أفضل وقت لقياس العلامات الحيوية:', 'بعد المجهود', 'أثناء الراحة', 'بعد القلق', 'بعد الأكل', 'B', 'القياس أثناء الراحة يعطي القيم الأساسية الصحيحة. المجهود والقلق والأكل تؤثر جميعها على العلامات الحيوية.', 'يفضل قياس العلامات الحيوية قبل إعطاء الأدوية كمقارنة مرجعية.', 1.0, 19),
(1, 1, 'التفسير السريري', 'الشحوب مع برودة الجلد يدل على:', 'صدمة', 'تحسس', 'عدوى', 'سمنة', 'A', 'الشحوب مع برودة الجلد ناتج عن تقلص الأوعية المحيطية الذي يحدث في الصدمة لحماية التروية الدماغية والقلبية.', 'في الصدمة التحسسية يحدث احمرار بدلا من الشحوب بسبب توسع الأوعية.', 1.0, 20),
(1, 1, 'التنفس', 'تسرع التنفس مع قلق شديد يدل على:', 'Hyperventilation', 'Bradypnea', 'Apnea', 'Cyanosis', 'A', 'فرط التهوية النفسي (Hyperventilation Syndrome) يسبب نفخ CO2 الزائد مما يؤدي لقلوية استقلابي وتنمل وأحيانا تشنجات.', 'التشخيص التفريقي مهم لاستبعاد الأسباب العضوية لتسرع التنفس.', 1.0, 21),
(1, 1, 'الحرارة', 'انخفاض الحرارة أقل من 35 درجة يسمى:', 'Fever', 'Hyperthermia', 'Hypothermia', 'Sepsis', 'C', 'انخفاض حرارة الجسم الأساسية عن 35 درجة مئوية يسمى Hypothermia ويصنف إلى خفيف (32-35)، متوسط (28-32)، وشديد (أقل من 28).', 'قد يبدو المريض في انخفاض الحرارة الشديدة وكأنه ميت بسبب بطء الأيض.', 1.0, 22),
(1, 1, 'النبض', 'النبض السباتي يفحص في:', 'حالات الطوارئ', 'الفحص الروتيني فقط', 'الأطفال فقط', 'كبار السن فقط', 'A', 'النبض السباتي يفحص في الطوارئ لتقييم النبض المركزي. لا يستخدم روتينيا لأن الضغط على الشريان السباتي قد يسبب بطء القلب أو إغماء.', 'لا تفحص النبضات السباتية من الجانبين في نفس الوقت لتجنب توقف الدماغ.', 1.0, 23),
(1, 1, 'إجراءات القياس', 'تسجيل العلامات الحيوية يجب أن يتم:', 'مرة واحدة يوميا', 'حسب حالة المريض', 'عند الخروج فقط', 'في بداية التمريض فقط', 'B', 'معدل قياس العلامات الحيوية يعتمد على حالة المريض: حالات حرجة كل 5-15 دقيقة، حالات مستقرة كل 4-8 ساعات، حالات روتينية مرة يوميا.', 'أي تغير مفاجئ في الحالة يستدعي زيادة تكرار القياس.', 1.0, 24),
(1, 1, 'التفسير السريري', 'أي تغير مفاجئ في العلامات الحيوية يدل على:', 'تحسن', 'خطورة', 'استقرار', 'نوم', 'B', 'التغير المفاجئ في العلامات الحيوية هو علامة تحذيرية مهمة تستدعي تقييم فوري وتصعيد العناية. لا تتجاهل أبدا.', 'SBAR هو بروتوكول التواصل المعتمد عند الإبلاغ عن تغيرات العلامات الحيوية.', 1.0, 25);

